// Parse system stats and check thresholds
const raw = $input.first().json.stdout || '{}';
let stats;
try {
  stats = JSON.parse(raw);
} catch {
  stats = { cpu_idle: 100, disk_usage_pct: 0, memory_pressure: 'normal', timestamp: new Date().toISOString() };
}

const cpu_usage = 100 - (parseFloat(stats.cpu_idle) || 0);
const disk_pct = parseInt(stats.disk_usage_pct) || 0;
const mem_pressure = stats.memory_pressure || 'normal';

const alerts = [];
if (cpu_usage > 80) alerts.push(`CPU: ${cpu_usage.toFixed(1)}%`);
if (disk_pct > 90) alerts.push(`Disk: ${disk_pct}%`);
if (mem_pressure !== 'normal' && mem_pressure !== 'The system has normal memory') alerts.push(`Memory: ${mem_pressure}`);

const has_alert = alerts.length > 0;

return [{
  json: {
    cpu_usage: cpu_usage.toFixed(1),
    disk_pct,
    memory_pressure: mem_pressure,
    timestamp: stats.timestamp,
    has_alert,
    alert_message: has_alert ? `⚠️ FAS Resource Alert:\n${alerts.join('\n')}` : 'All resources normal'
  }
}];
